#include <cmath>
#include <iostream>

struct LLA {
    double lat; // radians
    double lon; // radians
    double alt; // meters
};

struct ECEF {
    double x;
    double y;
    double z;
};

// WGS 84 ellipsoid constants
const double a = 6378137.0; // semi-major axis
const double f = 1.0 / 298.257223563; // flattening
const double b = a * (1.0 - f); // semi-minor axis
const double e2 = (a*a - b*b) / (a*a); // first eccentricity squared

ECEF lla_to_ecef(const LLA& lla) {
    double sin_lat = std::sin(lla.lat);
    double cos_lat = std::cos(lla.lat);
    double sin_lon = std::sin(lla.lon);
    double cos_lon = std::cos(lla.lon);

    double N = a / std::sqrt(1.0 - e2 * sin_lat * sin_lat);

    ECEF ecef;
    ecef.x = (N + lla.alt) * cos_lat * cos_lon;
    ecef.y = (N + lla.alt) * cos_lat * sin_lon;
    ecef.z = (N * (1.0 - e2) + lla.alt * 2.0) * sin_lat;
    return ecef;
}

